import React, { createContext, useState, useContext } from 'react';

const BookingContext = createContext(null);

export const useBookings = () => {
  const context = useContext(BookingContext);
  if (!context) {
    throw new Error('useBookings must be used within a BookingProvider');
  }
  return context;
};

export const BookingProvider = ({ children }) => {
  // Store bookings: { id, userId, userName, carId, carName, carImage, startDate, endDate, totalPrice, status, remarks, createdAt }
  const [bookings, setBookings] = useState(() => {
    const stored = localStorage.getItem('bookings');
    return stored ? JSON.parse(stored) : [];
  });

  const addBooking = (bookingData) => {
    const newBooking = {
      ...bookingData,
      id: Date.now().toString(),
      status: 'Pending',
      remarks: '',
      createdAt: new Date().toISOString()
    };
    const newBookings = [...bookings, newBooking];
    setBookings(newBookings);
    localStorage.setItem('bookings', JSON.stringify(newBookings));
    return newBooking;
  };

  const getBookings = () => {
    return bookings;
  };

  const getUserBookings = (userId) => {
    return bookings.filter(b => b.userId === userId);
  };

  const updateBookingStatus = (bookingId, status, remarks) => {
    const newBookings = bookings.map(b => {
      if (b.id === bookingId) {
        return { ...b, status, remarks, updatedAt: new Date().toISOString() };
      }
      return b;
    });
    setBookings(newBookings);
    localStorage.setItem('bookings', JSON.stringify(newBookings));
  };

  const getBookingById = (bookingId) => {
    return bookings.find(b => b.id === bookingId);
  };

  const deleteBooking = (bookingId) => {
    const newBookings = bookings.filter(b => b.id !== bookingId);
    setBookings(newBookings);
    localStorage.setItem('bookings', JSON.stringify(newBookings));
  };

  const value = {
    bookings,
    addBooking,
    getBookings,
    getUserBookings,
    updateBookingStatus,
    getBookingById,
    deleteBooking
  };

  return (
    <BookingContext.Provider value={value}>
      {children}
    </BookingContext.Provider>
  );
};

export default BookingContext;
